/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000000 + 7;
    const MAX_VAL = 5000;
    const MAX_S = 50;

    // 1. Helper function to calculate digit sum
    const getDigitSum = (n) => {
        let sum = 0;
        let str = String(n);
        for (let i = 0; i < str.length; i++) {
            sum += parseInt(str[i]);
        }
        return sum;
    };

    // 2. Precompute V[S]: List of numbers x <= 5000 where DigitSum(x) = S
    // V[S] will store sorted arrays of numbers.
    const V = new Array(MAX_S + 1).fill(0).map(() => []);

    for (let x = 0; x <= MAX_VAL; x++) {
        const s = getDigitSum(x);
        if (s <= MAX_S) {
            V[s].push(x);
        }
    }

    const N = digitSum.length;
    if (N === 0) return 0;

    // DP state: We use two arrays to store the DP results for the current step (DP_curr) 
    // and the previous step (DP_prev).

    // DP_prev[j] stores the count of valid sequences ending in V_prev[j]
    let DP_prev = []; 

    // --- Base Case: i = 0 ---
    const S0 = digitSum[0];
    const V0 = V[S0];

    if (V0.length === 0) {
        return 0;
    }

    // Initialize DP_prev: Every single element is a valid sequence of length 1
    DP_prev = new Array(V0.length).fill(1);

    // --- Transition: i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Si = digitSum[i];
        const Vi = V[Si];
        const Vi_minus_1 = V[digitSum[i-1]];

        if (Vi.length === 0) {
            return 0; // No valid number for this step
        }

        const DP_curr = new Array(Vi.length).fill(0);

        let cumulative_count = 0;
        let k = 0; // Pointer for Vi_minus_1

        for (let j = 0; j < Vi.length; j++) {
            const P_current = Vi[j];

            // Sum up DP_prev[k] for all k such that Vi_minus_1[k] <= P_current
            while (k < Vi_minus_1.length && Vi_minus_1[k] <= P_current) {
                cumulative_count = (cumulative_count + DP_prev[k]) % MOD;
                k++;
            }

            DP_curr[j] = cumulative_count;
        }

        DP_prev = DP_curr;
    }

    // 3. Final result: Sum all counts in the last DP array
    let total_count = 0;
    for (let i = 0; i < DP_prev.length; i++) {
        total_count = (total_count + DP_prev[i]) % MOD;
    }

    return total_count;
}

