#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Helper function to calculate digit sum
ll calculate_digit_sum(ll n) {
    ll sum = 0;
    string s = to_string(n);
    for (char c : s) {
        sum += c - '0';
    }
    return sum;
}

long long solve(std::vector<ll> digitSum) {
    const ll MOD = 1000000000 + 7;
    const ll MAX_VAL = 5000;
    const int MAX_S = 50;

    int N = digitSum.size();
    if (N == 0) return 0;

    // V[S] stores a sorted list of numbers x <= 5000 where DigitSum(x) = S.
    vector<vector<ll>> V(MAX_S + 1);

    // Precomputation
    for (ll x = 0; x <= MAX_VAL; x++) {
        ll s = calculate_digit_sum(x);
        if (s <= MAX_S) {
            V[s].push_back(x);
        }
    }

    // DP_prev[k] stores the count of valid sequences ending specifically at V[digitSum[i-1]][k]
    // Since the structure changes at each step i, we use dynamic arrays/vectors.

    // --- Base Case: i = 0 ---
    ll S0 = digitSum[0];
    const vector<ll>& V0 = V[S0];

    if (V0.empty()) {
        return 0;
    }

    // DP_prev stores counts for the sequence ending at index 0
    // Initialize DP_prev: Every single element is a valid sequence of length 1 (count = 1)
    vector<ll> DP_prev(V0.size(), 1);

    // --- Transition: i = 1 to N-1 ---
    for (int i = 1; i < N; i++) {
        ll Si = digitSum[i];
        const vector<ll>& Vi = V[Si];

        // Get the list of values from the previous step
        ll S_prev = digitSum[i-1];
        const vector<ll>& Vi_minus_1 = V[S_prev];

        if (Vi.empty()) {
            return 0; // No valid number for this step
        }
        if (Vi_minus_1.empty()) {
            // This should only happen if S_prev was impossible, but we check Vi.empty() first.
            // If Si is possible but S_prev was impossible, the count must be 0.
            // Since DP_prev is based on Vi_minus_1, if Vi_minus_1 is empty, DP_prev should be empty/zero length.
            if (DP_prev.empty()) return 0; 
        }


        vector<ll> DP_curr(Vi.size(), 0);

        ll cumulative_count = 0;
        int k = 0; // Pointer for Vi_minus_1

        // Iterate over potential current values P_current = Vi[j]
        for (int j = 0; j < Vi.size(); j++) {
            ll P_current = Vi[j];

            // Sum up DP_prev[k] for all k such that Vi_minus_1[k] <= P_current
            // Since Vi_minus_1 is sorted, we advance k until Vi_minus_1[k] > P_current
            while (k < Vi_minus_1.size() && Vi_minus_1[k] <= P_current) {
                cumulative_count = (cumulative_count + DP_prev[k]) % MOD;
                k++;
            }

            DP_curr[j] = cumulative_count;
        }

        DP_prev = DP_curr;
    }

    // 3. Final result: Sum all counts in the last DP array
    ll total_count = 0;
    for (ll count : DP_prev) {
        total_count = (total_count + count) % MOD;
    }

    return total_count;
