#include <string>
#include <algorithm>
#include <cmath>

using namespace std;

long long solve(std::vector<long long> digitSum) {
    const long long MOD = 1000000000 + 7;
    const int MAX_VAL = 5000;
    const int MAX_S = 50;

    // 1. Helper function to calculate digit sum
    auto getDigitSum = [](long long n) -> int {
        int sum = 0;
        if (n == 0) return 0;
        long long temp = n;
        while (temp > 0) {
            sum += (temp % 10);
            temp /= 10;
        }
        return sum;
    };

    // 2. Precompute V[S]: List of numbers x <= 5000 where DigitSum(x) = S
    // V[S] stores sorted arrays of numbers.
    // Since the numbers are small (<= 5000), we can use int for the values stored.
    std::vector<std::vector<int>> V(MAX_S + 1);

    for (int x = 0; x <= MAX_VAL; x++) {
        int s = getDigitSum(x);
        if (s <= MAX_S) {
            V[s].push_back(x);
        }
    }

    int N = digitSum.size();
    if (N == 0) return 0;

    // DP state: DP_prev[k] stores the count of valid sequences of length i ending in V_prev[k]
    std::vector<long long> DP_prev; 

    // --- Base Case: i = 0 ---
    int S0 = (int)digitSum[0];
    const std::vector<int>& V0 = V[S0];

    if (V0.empty()) {
        return 0;
    }

    // Initialize DP_prev: Every single element is a valid sequence of length 1
    DP_prev.resize(V0.size());
    std::fill(DP_prev.begin(), DP_prev.end(), 1);

    // --- Transition: i = 1 to N-1 ---
    for (int i = 1; i < N; i++) {
        int Si = (int)digitSum[i];
        const std::vector<int>& Vi = V[Si];
        int Si_minus_1 = (int)digitSum[i-1];
        const std::vector<int>& Vi_minus_1 = V[Si_minus_1];

        if (Vi.empty()) {
            return 0; // No valid number for this step
        }

        std::vector<long long> DP_curr(Vi.size(), 0);

        long long cumulative_count = 0;
        int k = 0; // Pointer for Vi_minus_1

        for (int j = 0; j < Vi.size(); j++) {
            int P_current = Vi[j];

            // Sum up DP_prev[k] for all k such that Vi_minus_1[k] <= P_current
            while (k < Vi_minus_1.size() && Vi_minus_1[k] <= P_current) {
                cumulative_count = (cumulative_count + DP_prev[k]) % MOD;
                k++;
            }

            DP_curr[j] = cumulative_count;
        }

        DP_prev = DP_curr;
    }

